mapper.select:
SELECT DATE(create_time) AS statDate, COUNT(*) AS totalInteractions, COUNT(DISTINCT visitor_id) AS uniqueVisitors, IFNULL(AVG(response_time_ms), 0) AS avgResponseTimeMs, IFNULL(AVG(feedback_score), 0) AS avgSatisfaction, SUM(IF(interaction_type = 'text', 1, 0)) AS textCount, SUM(IF(interaction_type = 'voice', 1, 0)) AS voiceCount FROM manage_visitor_interaction WHERE create_time >= DATE_SUB(CURDATE(), INTERVAL #{days} DAY)
AND scenic_id = #{scenicId}
GROUP BY DATE(create_time) ORDER BY statDate ASC

SELECT user_question AS question, COUNT(*) AS count FROM manage_visitor_interaction WHERE user_question IS NOT NULL AND user_question != ''
AND scenic_id = #{scenicId}
GROUP BY user_question ORDER BY count DESC LIMIT #{limit}

SELECT IFNULL(device_type, 'unknown') AS deviceType, COUNT(*) AS count FROM manage_visitor_interaction WHERE 1 = 1
AND scenic_id = #{scenicId}
GROUP BY device_type

SELECT DATE(create_time) AS date, SUM(IF(emotion_detected = 'positive', 1, 0)) AS positiveCount, SUM(IF(emotion_detected = 'neutral', 1, 0)) AS neutralCount, SUM(IF(emotion_detected = 'negative', 1, 0)) AS negativeCount FROM manage_visitor_interaction WHERE DATE(create_time) BETWEEN #{startDate} AND #{endDate}
AND scenic_id = #{scenicId}
GROUP BY DATE(create_time) ORDER BY date ASC

SELECT IFNULL(intent_type, 'other') AS intentType, COUNT(*) AS count FROM manage_visitor_interaction WHERE intent_type IS NOT NULL AND intent_type != ''
AND scenic_id = #{scenicId}
GROUP BY intent_type ORDER BY count DESC LIMIT #{limit}

SELECT DATE(create_time) AS date, IFNULL(AVG(feedback_score), 0) AS avgScore FROM manage_visitor_interaction WHERE create_time >= DATE_SUB(CURDATE(), INTERVAL #{days} DAY) AND feedback_score IS NOT NULL
AND scenic_id = #{scenicId}
GROUP BY DATE(create_time) ORDER BY date ASC
